<template>
  <div v-if="data" class="hud">
    <section class="hero-card">
      <div class="hero-head">
        <button type="button" class="hero-avatar" @click="triggerAvatarUpload">
          <img v-if="avatarUrl" :src="avatarUrl" alt="角色头像" />
          <div v-else class="hero-avatar-placeholder">上传头像</div>
        </button>

        <input
          ref="avatarInputRef"
          type="file"
          accept="image/*"
          class="avatar-input"
          @change="onAvatarChange"
        />

        <div class="hero-content">
          <div class="hero-main">
            <div>
              <p class="eyebrow">{{ data.player.profession }}</p>
              <h1>{{ data.player.name }}</h1>
              <p class="meta">
                Lv.{{ data.player.level }} | {{ data.world.location }} | {{ data.world.time }} | {{ data.world.weather }}
              </p>
            </div>
            <div class="chips">
              <span class="chip chip-currency">
                <span class="chip-label">金钱</span>
                <strong class="chip-value">{{ data.player.gold }}</strong>
              </span>
              <span class="chip">
                <span class="chip-label">区域状态</span>
                <strong class="chip-value">{{ data.world.exploration }}</strong>
              </span>
              <span class="chip danger">
                <span class="chip-label">危险等级</span>
                <strong class="chip-value">{{ data.world.danger }}</strong>
              </span>
              <span v-if="data.combat.inBattle" class="chip">
                <span class="chip-label">ROUND</span>
                <strong class="chip-value">{{ data.combat.round }}</strong>
              </span>
            </div>
          </div>

          <div class="bars">
            <div class="bar-block">
              <div class="bar-label"><span>HP</span><span>{{ data.player.hp }}/{{ effectiveMaxHp }}</span></div>
              <div class="bar">
                <div class="fill hp" :style="{ width: percent(data.player.hp, effectiveMaxHp) }" />
              </div>
            </div>
            <div class="bar-block">
              <div class="bar-label"><span>体力</span><span>{{ data.player.stamina }}/100</span></div>
              <div class="bar">
                <div class="fill stamina" :style="{ width: `${data.player.stamina}%` }" />
              </div>
            </div>
            <div class="bar-block">
              <div class="bar-label"><span>经验</span><span>{{ data.player.exp }}/{{ data.player.expToNext }}</span></div>
              <div class="bar">
                <div class="fill exp" :style="{ width: percent(data.player.exp, data.player.expToNext) }" />
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>

    <section class="grid">
      <article class="panel attribute-panel full-span">
        <div class="section-head">
          <h2>属性面板</h2>
          <span class="hint">实时属性</span>
        </div>
        <div class="attribute-strip">
          <span v-for="entry in attributePrimaryStats" :key="entry.key" class="attribute-pill">
            <img
              v-if="entry.icon"
              class="attribute-pill__icon"
              width="16"
              height="16"
              alt=""
              aria-hidden="true"
              :src="svgToDataUrl(entry.icon)"
            />
            <span>{{ entry.label }} {{ entry.value }}</span>
          </span>
          <span>基础ATK {{ data.player.baseStats?.atk ?? effectiveCombatStats.atk }}</span>
          <button type="button" class="attribute-action" @click.stop.prevent="openBreakdown('gear')">
            装备+ {{ effectiveEquipmentBonus.atk }} / {{ effectiveEquipmentBonus.def }}
          </button>
          <button type="button" class="attribute-action" @click.stop.prevent="openBreakdown('hp')">
            生命+ {{ effectiveEquipmentBonus.maxHp }}
          </button>
          <button type="button" class="attribute-action" @click.stop.prevent="openBreakdown('notes')">
            词条 {{ effectiveBonusNotes.length }}
          </button>
        </div>
      </article>

      <article class="panel inventory-panel full-span">
        <div class="section-head">
          <h2>装备</h2>
          <span class="hint">点击查看详情</span>
        </div>
        <div class="equipment-grid">
          <button
            v-for="entry in equipmentEntries"
            :key="entry.key"
            type="button"
            :class="['equipment-card', gradeClass(entry.grade)]"
            @click.stop.prevent="openDetail(entry)"
          >
            <span class="equipment-card__name">{{ entry.name }}</span>
            <span class="equipment-card__icon" aria-hidden="true" v-html="equipmentCardIcons[entry.key as EquipmentKey]" />
          </button>
        </div>
      </article>

      <article class="panel supply-panel full-span">
        <div class="section-head">
          <h2>补给</h2>
          <span class="hint">点击查看详情</span>
        </div>
        <div class="supply-tabs" role="tablist" aria-label="inventory categories">
          <button
            v-for="tab in inventoryTabs"
            :key="tab"
            type="button"
            class="supply-tab"
            :class="{ 'is-active': activeInventoryTab === tab }"
            @click="activeInventoryTab = tab"
          >
            {{ tab }}
          </button>
        </div>
        <div class="supply-grid">
          <button
            v-for="entry in visibleInventoryEntries"
            :key="entry.key"
            type="button"
            :class="['supply-card', gradeClass(entry.grade)]"
            @click.stop.prevent="openDetail(entry)"
          >
            <span class="supply-card__name">{{ entry.name }}</span>
            <span class="supply-card__icon" aria-hidden="true" v-html="resolveInventoryEntryIcon(entry)" />
            <strong class="supply-card__value">{{ entry.value }}</strong>
          </button>
        </div>
        <p v-if="!visibleInventoryEntries.length" class="inventory-empty-text">暂无物品</p>
      </article>

      <article class="panel survival-panel full-span">
        <button type="button" class="survival-toggle" @click="toggleSurvival">
          <span>生存状态</span>
          <span>{{ isSurvivalOpen ? '收起' : '展开' }}</span>
        </button>
        <div v-if="isSurvivalOpen" class="survival-row">
          <div v-for="entry in survivalEntries" :key="entry.label" class="survival-pill">
            <span class="survival-pill__main">
              <span class="survival-pill__icon" aria-hidden="true" v-html="entry.icon" />
              <span>{{ entry.label }}</span>
            </span>
            <strong>{{ entry.value }}</strong>
          </div>
        </div>
      </article>
    </section>

    <Teleport to="body">
      <div
        v-if="selectedDetail"
        class="detail-backdrop"
        :style="{
          '--text-main': '#eaf6ff',
          '--text-soft': '#c7d8e5',
          '--text-sub': '#93aabc',
        }"
        @click.self="closeDetail"
      >
        <article class="detail-modal" @click.stop>
          <div class="detail-shell">
            <header class="detail-head">
              <div class="detail-header-copy">
                <p class="detail-kicker">{{ selectedDetail.kindLabel }} | {{ selectedDetail.slotOrCategory }}</p>
                <div class="detail-title-row">
                  <h3 :class="['detail-title', gradeClass(selectedDetail.grade)]">{{ selectedDetail.name }}</h3>
                  <span v-if="selectedDetail.grade" :class="['detail-grade', gradeClass(selectedDetail.grade)]">
                    {{ selectedDetail.grade }}
                  </span>
                </div>
              </div>
              <button
                type="button"
                class="close-button"
                style="color: #eaf6ff !important; -webkit-text-fill-color: #eaf6ff;"
                @click.stop.prevent="closeDetail"
              >
                关闭
              </button>
            </header>

            <section class="detail-block">
              <p
                class="detail-summary"
                style="color: #eaf6ff !important; -webkit-text-fill-color: #eaf6ff;"
              >
                {{ selectedDetail.summary }}
              </p>
              <p
                v-if="selectedDetail.flavor"
                class="detail-flavor"
                style="color: #c7d8e5 !important; -webkit-text-fill-color: #c7d8e5;"
              >
                {{ selectedDetail.flavor }}
              </p>
            </section>

            <section v-if="selectedDetail.stats.length" class="detail-block">
              <p class="detail-section-label">基础属性</p>
              <div class="detail-stats">
                <div v-for="stat in selectedDetail.stats" :key="stat.label" class="detail-stat">
                  <span>{{ stat.label }}</span>
                  <strong>{{ stat.value }}</strong>
                </div>
              </div>
            </section>

            <section v-if="selectedDetail.effects.length" class="detail-block">
              <p class="detail-section-label">效果词条</p>
              <div class="effects-list">
                <div v-for="effect in selectedDetail.effects" :key="effect.name" class="effect-card">
                  <strong style="color: #eaf6ff !important; -webkit-text-fill-color: #eaf6ff;">
                    {{ effect.name }}
                  </strong>
                  <p style="color: #c7d8e5 !important; -webkit-text-fill-color: #c7d8e5;">
                    {{ effect.description }}
                  </p>
                </div>
              </div>
            </section>

            <footer v-if="canEquip || canUnequip" class="detail-actions">
              <button
                v-if="canEquip"
                type="button"
                class="detail-action-btn detail-action-equip"
                @click.stop.prevent="equipFromInventory(selectedDetail!.inventoryGearIndex!)"
              >
                装备
              </button>
              <button
                v-if="canUnequip"
                type="button"
                class="detail-action-btn detail-action-unequip"
                @click.stop.prevent="unequipSlot(selectedDetail!.key as EquipmentKey)"
              >
                脱下
              </button>
            </footer>
          </div>
        </article>
      </div>
    </Teleport>

    <Teleport to="body">
      <div
        v-if="selectedBreakdown"
        class="detail-backdrop"
        :style="{
          '--text-main': '#eaf6ff',
          '--text-soft': '#c7d8e5',
          '--text-sub': '#93aabc',
        }"
        @click.self="closeBreakdown"
      >
        <article class="detail-modal breakdown-modal" @click.stop>
          <div class="detail-shell">
            <header class="detail-head">
              <div class="detail-header-copy">
                <p class="detail-kicker">属性来源</p>
                <div class="detail-title-row">
                  <h3 class="detail-title">{{ selectedBreakdown.title }}</h3>
                </div>
              </div>
              <button
                type="button"
                class="close-button"
                style="color: #eaf6ff !important; -webkit-text-fill-color: #eaf6ff;"
                @click.stop.prevent="closeBreakdown"
              >
                关闭
              </button>
            </header>

            <section class="detail-block">
              <p
                class="detail-summary"
                style="color: #eaf6ff !important; -webkit-text-fill-color: #eaf6ff;"
              >
                {{ selectedBreakdown.summary }}
              </p>
            </section>

            <section class="detail-block">
              <div class="effects-list compact">
                <div v-for="item in selectedBreakdown.items" :key="item.label" class="effect-card">
                  <strong style="color: #eaf6ff !important; -webkit-text-fill-color: #eaf6ff;">
                    {{ item.label }}
                  </strong>
                  <p style="color: #c7d8e5 !important; -webkit-text-fill-color: #c7d8e5;">
                    {{ item.description }}
                  </p>
                </div>
                <div v-if="!selectedBreakdown.items.length" class="effect-card">
                  <p style="color: #c7d8e5 !important; -webkit-text-fill-color: #c7d8e5;">
                    当前没有可显示的属性来源。
                  </p>
                </div>
              </div>
            </section>
          </div>
        </article>
      </div>
    </Teleport>
  </div>
</template>

<script setup lang="ts">
import { computed, onMounted, ref, watch } from 'vue';
import { useDataStore } from './store';

type EffectItem = {
  name: string;
  description: string;
};

type ItemMetaSource = {
  slot?: string;
  category?: string;
  grade?: string;
  summary?: string;
  flavor?: string;
  maxHp?: number;
  atk?: number;
  def?: number;
  speed?: number;
  crit?: number;
  effects?: EffectItem[];
};

type DetailEntry = {
  key: string;
  kind: 'equipment' | 'supply';
  kindLabel: string;
  label: string;
  name: string;
  value?: string | number;
  slotOrCategory: string;
  grade?: string;
  summary: string;
  flavor: string;
  stats: Array<{ label: string; value: string }>;
  effects: EffectItem[];
  /** 来自部位槽（可脱下）或背包装备栏（可装备） */
  source?: 'slot' | 'inventory-gear';
  /** 仅当 source === 'inventory-gear' 时有效，为 inventory.equipment 的下标 */
  inventoryGearIndex?: number;
};

type BreakdownEntry = {
  label: string;
  description: string;
};

type BreakdownSheet = {
  title: string;
  summary: string;
  items: BreakdownEntry[];
};

type InventoryTab = '\u88c5\u5907' | '\u6d88\u8017\u54c1' | '\u6750\u6599' | '\u91cd\u8981\u7269\u54c1';
type SupplyInventoryTab = Exclude<InventoryTab, '\u88c5\u5907'>;

type InventoryItemSource = ItemMetaSource & {
  id?: string;
  name?: string;
  slot?: string;
  quantity?: number;
};

const store = useDataStore();
const data = computed(() => store.data);
const selectedDetail = ref<DetailEntry | null>(null);
const selectedBreakdown = ref<BreakdownSheet | null>(null);
const isSurvivalOpen = ref(false);
const activeInventoryTab = ref<InventoryTab>('\u88c5\u5907');
const avatarInputRef = ref<HTMLInputElement | null>(null);
const avatarUrl = ref<string | null>(null);
const STORAGE_AVATAR_KEY = 'wasteland_status_avatar';
const syncedLootMessageIds = new Set<number>();
const inventoryTabs: InventoryTab[] = ['\u88c5\u5907', '\u6d88\u8017\u54c1', '\u6750\u6599', '\u91cd\u8981\u7269\u54c1'];

const equipmentLabels = {
  mainWeapon: '\u4e3b\u6b66\u5668',
  subWeapon: '\u526f\u6b66\u5668',
  head: '\u5934\u90e8',
  chest: '\u8eaf\u5e72',
  hands: '\u624b\u90e8',
  legs: '\u817f\u90e8',
  feet: '\u8db3\u90e8',
  accessory1: '\u9970\u54c11',
  accessory2: '\u9970\u54c12',
} as const;

const supplyLabels = {
  ammo: '\u5b50\u5f39',
  medkit: '\u533b\u7597\u5305',
  scrap: '\u5e9f\u6599',
  gold: '\u91d1\u5e01',
} as const;

type EquipmentKey = keyof typeof equipmentLabels;
type SupplyKey = keyof typeof supplyLabels;

const equipmentKeys = Object.keys(equipmentLabels) as EquipmentKey[];
const supplyKeys = Object.keys(supplyLabels) as SupplyKey[];
const supplyInventoryTabs = inventoryTabs.slice(1) as SupplyInventoryTab[];

const equipmentCardIcons: Record<EquipmentKey, string> = {
  mainWeapon:
