/** 将 SVG 字符串转为 data URL，避免在酒馆 iframe 中 v-html 被过滤导致图标不显示 */
const ICON_COLOR = 'rgba(198,236,255,0.92)';
function svgToDataUrl(svgString: string): string {
  if (!svgString || typeof svgString !== 'string') return '';
  const filled = svgString
    .replace(/fill="currentColor"/gi, `fill="${ICON_COLOR}"`)
    .replace(/stroke="currentColor"/gi, `stroke="${ICON_COLOR}"`);
  const encoded = encodeURIComponent(filled).replace(/'/g, '%27');
  return `data:image/svg+xml,${encoded}`;
}

