const STATUSBAR_LOOT_REG =
  /获得\s*[：:]?\s*(?:\[([^\]]+)\]|【([^】]+)】|([^\s\[\]【】×xX\d]+?))\s*[×xX]\s*(\d+)/g;
const STATUSBAR_SETTLEMENT_REG = /^([^：:\n]+?)\s*[：:]\s*(\d+)(?:\s*\([^)]*\))?/gm;
const STATUSBAR_CATEGORY_PREFIX_REG =
  /(?:^|\n)\s*(装备|消耗品|补给|材料|重要物品|重要道具)\s*[：:]\s*([^\n×xX\d]{2,40}?)\s*[×xX]\s*(\d+)/gm;
const STATUSBAR_LOOSE_LOOT_REG =
  /(?:^|[\s、，,，])([^\s×xX\d]{2,24}?)\s*[×xX]?\s*(\d+)\s*(?:[个份发枚]|$)/gm;

type LootSyncCategory = '装备' | '消耗品' | '材料' | '重要道具';

type ParsedLootEntry = {
  name: string;
  quantity: number;
  category: LootSyncCategory;
};

function classifyLootItem(name: string): LootSyncCategory {
  const normalized = name.trim();
  if (!normalized) return '材料';

  if (
    /手枪|步枪|霰弹枪|冲锋枪|狙击枪|弓|弩|猎枪|武器|短刀|匕首|军刀|砍刀|长刀|斧|锤|长枪|头盔|头巾|面罩|护甲|胸甲|披风|外套|手套|护腕|工装裤|护腿|裤|靴|鞋|戒指|项链|吊坠|护符|徽章|指南针|饰品/i.test(
      normalized,
    )
  ) {
    return '装备';
  }

  if (
    /子弹|弹药|弹匣|霰弹|箭矢|医疗|绷带|药品|消毒|止血|治疗|口粮|肉块|生肉|熟肉|蟹肉|可烹饪|净水|饮用水|干粮|罐头|蛋白块|手雷|烟雾弹|闪光|燃烧瓶|投掷物|电池/i.test(
      normalized,
    )
  ) {
    return '消耗品';
  }

  if (/任务物品|关键道具|信物|钥匙|情报|委托物|芯片|密信|证物|纪念物/i.test(normalized)) {
    return '重要道具';
  }

  return '材料';
}

function isSettlementCurrencyOrInvalid(name: string) {
  const normalized = name.trim();
  return /复兴币|金穗|^[\d\s]+g$|\(g\)/i.test(normalized) || normalized.length < 2;
}

function isLikelyLootName(name: string) {
  const normalized = name.trim();
  if (normalized.length < 2 || normalized.length > 30) return false;
  if (/^\d+$|^第\d+[楼条个]?$/i.test(normalized)) return false;
  if (!/[\u4e00-\u9fff]/.test(normalized)) return false;
  if (/^(血量|生命|体力|经验|等级|伤害)/.test(normalized)) return false;
  return true;
}

function normalizeLootText(text: string) {
  return text
    .replace(/^\s*(?:本次)?(?:战利品|掉落|获得)[：:]\s*/gm, '')
    .replace(/\r/g, '')
    .trim();
}

function parseLootEntriesFromMessage(message: string): ParsedLootEntry[] {
  const normalizedMessage = normalizeLootText(message);
  const byName = new Map<string, number>();
  const forcedCategoryByName = new Map<string, LootSyncCategory>();
  let match: RegExpExecArray | null;

  STATUSBAR_CATEGORY_PREFIX_REG.lastIndex = 0;
  while ((match = STATUSBAR_CATEGORY_PREFIX_REG.exec(normalizedMessage)) !== null) {
    const rawCategory = (match[1] || '').trim();
    const name = (match[2] || '').trim().replace(/\s+/g, ' ').slice(0, 80);
    const quantity = Math.max(1, parseInt(match[3], 10) || 1);
    if (name.length < 2) continue;

    const category: LootSyncCategory =
      rawCategory === '装备'
        ? '装备'
        : rawCategory === '材料'
          ? '材料'
          : rawCategory === '重要物品' || rawCategory === '重要道具'
            ? '重要道具'
            : '消耗品';

    byName.set(name, (byName.get(name) ?? 0) + quantity);
    forcedCategoryByName.set(name, category);
  }

  STATUSBAR_LOOT_REG.lastIndex = 0;
  while ((match = STATUSBAR_LOOT_REG.exec(normalizedMessage)) !== null) {
    const name = (match[1] || match[2] || match[3] || '').trim().replace(/\s+/g, ' ').slice(0, 80);
    const quantity = Math.max(1, parseInt(match[4], 10) || 1);
    if (name.length < 2) continue;
    byName.set(name, (byName.get(name) ?? 0) + quantity);
  }

  STATUSBAR_SETTLEMENT_REG.lastIndex = 0;
  while ((match = STATUSBAR_SETTLEMENT_REG.exec(normalizedMessage)) !== null) {
    const name = (match[1] || '').trim().replace(/\s+/g, ' ').slice(0, 80);
    if (isSettlementCurrencyOrInvalid(name)) continue;
    const quantity = Math.max(1, parseInt(match[2], 10) || 1);
    byName.set(name, (byName.get(name) ?? 0) + quantity);
  }

  STATUSBAR_LOOSE_LOOT_REG.lastIndex = 0;
  while ((match = STATUSBAR_LOOSE_LOOT_REG.exec(normalizedMessage)) !== null) {
    const name = (match[1] || '').trim().replace(/\s+/g, ' ').slice(0, 80);
    if (!isLikelyLootName(name) || isSettlementCurrencyOrInvalid(name)) continue;
    const quantity = Math.max(1, parseInt(match[2], 10) || 1);
    byName.set(name, (byName.get(name) ?? 0) + quantity);
  }

  return [...byName.entries()].map(([name, quantity]) => ({
    name,
    quantity,
    category: forcedCategoryByName.get(name) ?? classifyLootItem(name),
  }));
}

function cloneInventoryItem(item: InventoryItemSource) {
  return {
    ...item,
    effects: Array.isArray(item.effects) ? [...item.effects] : [],
  };
}

function createInventorySupplyItem(entry: ParsedLootEntry, index: number) {
  return {
    id: `hud-loot-${Date.now()}-${index}-${Math.random().toString(36).slice(2)}`,
    name: entry.name,
    category: entry.category === '重要道具' ? '重要道具' : entry.category,
    quantity: entry.quantity,
  };
}

function createInventoryEquipmentItem(entry: ParsedLootEntry, index: number) {
  return {
    id: `hud-gear-${Date.now()}-${index}-${Math.random().toString(36).slice(2)}`,
    name: entry.name,
    slot: '',
    grade: '',
    summary: '战后搜刮得到的装备，可在状态栏中查看并手动装备。',
    flavor: '',
    maxHp: 0,
    atk: 0,
    def: 0,
    speed: 0,
    crit: 0,
    effects: [],
    quantity: entry.quantity,
  };
}

function inventoryAlreadyHasEntry(inventory: Record<string, InventoryItemSource[]>, entry: ParsedLootEntry) {
  const targetList =
    entry.category === '装备'
      ? inventory.equipment || []
      : entry.category === '消耗品'
        ? inventory.consumables || []
        : entry.category === '材料'
          ? inventory.materials || []
          : inventory.important || [];

  return targetList.some((item) => (item.name || '').trim() === entry.name);
}

function syncLootInventoryFromLatestMessage() {
  const latestMessage = getChatMessages(-1)?.[0];
  if (!latestMessage || latestMessage.is_user || typeof latestMessage.message_id !== 'number') return;
  if (syncedLootMessageIds.has(latestMessage.message_id)) return;

  const messageScope = { type: 'message' as const, message_id: latestMessage.message_id };
  const scopedVariables = getVariables(messageScope) || {};
  const lootHint = (scopedVariables.stat_data?.log?.lootHint || data.value?.log?.lootHint || '').toString();
  if (!lootHint || /暂无掉落/.test(lootHint)) return;

  const loots = parseLootEntriesFromMessage(lootHint);
  if (!loots.length) return;
  const currentInventory = (scopedVariables.stat_data?.inventory || {}) as Record<string, InventoryItemSource[]>;

  if (loots.every((entry) => inventoryAlreadyHasEntry(currentInventory, entry))) {
    syncedLootMessageIds.add(latestMessage.message_id);
    return;
  }

  updateVariablesWith((variables) => {
    const statData = (variables.stat_data ||= {});
    const inventorySource = (statData.inventory || {}) as Record<string, InventoryItemSource[]>;
    const inventory = {
      equipment: (inventorySource.equipment || []).map(cloneInventoryItem),
      consumables: (inventorySource.consumables || []).map(cloneInventoryItem),
      ammo: (inventorySource.ammo || []).map(cloneInventoryItem),
      materials: (inventorySource.materials || []).map(cloneInventoryItem),
      important: (inventorySource.important || []).map(cloneInventoryItem),
    };

    loots.forEach((entry, index) => {
      if (entry.category === '装备') {
        const existing = inventory.equipment.find((item) => (item.name || '').trim() === entry.name);
        if (existing) {
          existing.quantity = Number(existing.quantity || 0) + entry.quantity;
          return;
        }
        inventory.equipment.push(createInventoryEquipmentItem(entry, index));
        return;
      }

      const target =
        entry.category === '消耗品'
          ? inventory.consumables
          : entry.category === '材料'
            ? inventory.materials
            : inventory.important;
      const existing = target.find((item) => (item.name || '').trim() === entry.name);
      if (existing) {
        existing.quantity = Number(existing.quantity || 0) + entry.quantity;
        return;
      }
      target.push(createInventorySupplyItem(entry, index));
    });

    statData.inventory = inventory;
    return variables;
  }, messageScope);

  syncedLootMessageIds.add(latestMessage.message_id);
}

function percent(current: number, max: number) {
  if (!max) return '0%';
  return `${Math.max(0, Math.min(100, (current / max) * 100))}%`;
}

function collectStats(source: Record<string, unknown> | undefined) {
  if (!source) return [];
  const rows = [
    ['攻击', source.atk],
    ['防御', source.def],
    ['速度', source.speed],
    ['暴击', source.crit],
    ['生命', source.maxHp],
  ] as const;

  return rows
    .filter(([, value]) => Number(value || 0) > 0)
    .map(([label, value]) => ({
      label,
      value: label === '暴击' ? `+${value}%` : `+${value}`,
    }));
}

function mergeMeta(primary: ItemMetaSource | undefined, fallback: ItemMetaSource | undefined): ItemMetaSource {
  const normalizeText = (value?: string) => {
    const text = (value || '').trim();
    return text && text !== '无' ? text : '';
  };

  return {
    slot: normalizeText(primary?.slot) || normalizeText(fallback?.slot) || '',
    category: normalizeText(primary?.category) || normalizeText(fallback?.category) || '',
    grade: normalizeText(primary?.grade) || normalizeText(fallback?.grade) || '',
    summary: normalizeText(primary?.summary) || normalizeText(fallback?.summary) || '',
    flavor: normalizeText(primary?.flavor) || normalizeText(fallback?.flavor) || '',
    maxHp: Number(primary?.maxHp || fallback?.maxHp || 0),
    atk: Number(primary?.atk || fallback?.atk || 0),
    def: Number(primary?.def || fallback?.def || 0),
    speed: Number(primary?.speed || fallback?.speed || 0),
    crit: Number(primary?.crit || fallback?.crit || 0),
    effects:
      (Array.isArray(primary?.effects) && primary.effects.length ? primary.effects : undefined) ||
      (Array.isArray(fallback?.effects) ? fallback.effects : []),
  };
}

function normalizeGrade(grade?: string) {
  const text = (grade || '').trim();
  if (!text) return 'normal';
  if (text.includes('\u4f20\u8bf4')) return 'legendary';
  if (text.includes('\u53f2\u8bd7')) return 'epic';
  if (text.includes('\u7a00\u6709')) return 'rare';
  if (text.includes('\u7cbe\u54c1') || text.includes('\u7cbe\u5236')) return 'fine';
  if (text.includes('\u666e\u901a')) return 'normal';
  return 'normal';
}

function gradeClass(grade?: string) {
  return `grade-${normalizeGrade(grade)}`;
}

function resolveDisplayText(...values: Array<string | undefined>) {
  const match = values
    .map((value) => (value || '').trim())
    .find((value) => value && value !== '无');
  return match || '';
}

function isCurrencyLikeValue(...values: Array<string | undefined>) {
  return values.some((value) => {
    const text = (value || '').trim();
    return text.includes('金币') || text.includes('货币') || text.includes('赏金');
  });
}

function inferSupplyInventoryTab(entry: DetailEntry): SupplyInventoryTab {
  if (entry.key === 'medkit' || entry.key === 'ammo') return '消耗品';
  if (entry.key === 'scrap') return '材料';
  if (entry.key === 'gold') return '重要物品';
  if (supplyInventoryTabs.includes(activeInventoryTab.value as SupplyInventoryTab)) {
    return activeInventoryTab.value as SupplyInventoryTab;
  }
  return '消耗品';
}

function resolveSupplyCardIcon(entry: DetailEntry) {
  return supplyCardIcons[inferSupplyInventoryTab(entry)];
}

/** 补给栏列表条目图标：装备子选项卡用部位图标，其余用消耗品/材料/重要物品分类图标 */
function resolveInventoryEntryIcon(entry: DetailEntry) {
  if (entry.source === 'inventory-gear' && entry.slotOrCategory) {
    const key = slotLabelToKey[entry.slotOrCategory];
    if (key && equipmentCardIcons[key]) return equipmentCardIcons[key];
  }
  return resolveSupplyCardIcon(entry);
}

function resolveSupplyFallback(item: InventoryItemSource, tab: InventoryTab) {
  const name = resolveDisplayText(item.name, item.category);
  if (name.includes('子弹') || name.includes('弹药')) return supplyFallbackMeta.ammo;
  if (name.includes('医疗') || name.includes('药') || name.includes('绷带')) return supplyFallbackMeta.medkit;
  if (name.includes('废料') || name.includes('零件') || name.includes('材料')) return supplyFallbackMeta.scrap;
  if (name.includes('金币') || name.includes('货币') || name.includes('赏金')) return supplyFallbackMeta.gold;

  if (tab === '材料') return supplyFallbackMeta.scrap;

  return undefined;
}

const equipmentEntries = computed<DetailEntry[]>(() => {
  if (!data.value) return [];

  return equipmentKeys.map((key) => {
    const label = equipmentLabels[key];
    const name = data.value.equipment?.[key] || '\u7a7a';
    const meta = mergeMeta(data.value.equipmentMeta?.[key], equipmentFallbackMeta[name]);

    return {
      key,
      kind: 'equipment',
      kindLabel: '\u88c5\u5907',
      label,
      name,
      slotOrCategory: (name === '\u7a7a' ? label : meta.slot) || label,
      grade: meta.grade || '',
      summary: meta.summary || `${name} \u5f53\u524d\u6682\u65e0\u8be6\u7ec6\u63cf\u8ff0\u3002`,
      flavor: meta.flavor || '',
      stats: collectStats(meta),
      effects: Array.isArray(meta.effects) ? meta.effects : [],
      source: 'slot',
    };
  });
});

const supplyEntries = computed<DetailEntry[]>(() => {
  if (!data.value) return [];

  return supplyKeys.map((key) => {
    const label = supplyLabels[key];
    const meta = mergeMeta(data.value.supplyMeta?.[key], supplyFallbackMeta[key]);
    const value = data.value.player?.[key] ?? 0;

    return {
      key,
      kind: 'supply',
      kindLabel: '\u9053\u5177',
      label,
      name: resolveDisplayText(data.value.supplyMeta?.[key]?.name, label) || label,
      value,
      slotOrCategory: meta.category || '\u8865\u7ed9',
      grade: '',
      summary: meta.summary || `${label} \u5f53\u524d\u6682\u65e0\u8be6\u7ec6\u63cf\u8ff0\u3002`,
      flavor: meta.flavor || '',
      stats: [{ label: '\u6301\u6709', value: String(value) }],
      effects: Array.isArray(meta.effects) ? meta.effects : [],
    };
  });
});

function buildInventoryGearEntry(item: InventoryItemSource, index: number): DetailEntry {
  const name = resolveDisplayText(item.name, '\u7a7a') || '\u7a7a';
  const meta = mergeMeta(item, equipmentFallbackMeta[name]);

  return {
    key: item.id || `inventory-gear-${index}`,
    kind: 'equipment',
    kindLabel: '\u80cc\u5305\u88c5\u5907',
    label: meta.slot || '\u5f85\u88c5\u5907',
    name,
    value: item.quantity || 1,
    slotOrCategory: meta.slot || '\u80cc\u5305',
    grade: meta.grade || '',
    summary: meta.summary || `${name} \u5f53\u524d\u6682\u65e0\u8be6\u7ec6\u63cf\u8ff0\u3002`,
    flavor: meta.flavor || '',
    stats: collectStats(meta),
    effects: Array.isArray(meta.effects) ? meta.effects : [],
    source: 'inventory-gear',
    inventoryGearIndex: index,
  };
}

function buildInventorySupplyEntry(item: InventoryItemSource, tab: InventoryTab, index: number): DetailEntry {
  const fallback = resolveSupplyFallback(item, tab);
  const meta = mergeMeta(item, fallback);
  const name = resolveDisplayText(item.name, item.category, tab) || tab;
  const category = resolveDisplayText(item.category, meta.category, tab) || tab;

  return {
    key: item.id || `inventory-${tab}-${index}`,
    kind: 'supply',
    kindLabel: '\u80cc\u5305\u9053\u5177',
    label: category,
    name,
    value: item.quantity || 1,
    slotOrCategory: category,
    grade: resolveDisplayText(item.grade, meta.grade),
    summary: meta.summary || `${name} \u5f53\u524d\u6682\u65e0\u8be6\u7ec6\u63cf\u8ff0\u3002`,
    flavor: meta.flavor || '',
    stats: [{ label: '\u6301\u6709', value: String(item.quantity || 1) }],
    effects: Array.isArray(meta.effects) ? meta.effects : [],
  };
}

function isValidInventoryEntryName(item: InventoryItemSource) {
  const name = (item.name || '').trim();
  if (!name) return false;
  if (isCurrencyLikeValue(item.name, item.category)) return false;
  if (/^[-－]/.test(name)) return false;
  if (/^\d+$/.test(name)) return false;
  if (/^\d{3,4}年\d{1,2}月\d{1,2}日/.test(name)) return false;
  if (/^(时间|当前进度|进度|伤害|暴击|生命|体力|经验|日期)$/.test(name)) return false;
  return true;
}

const inventoryEquipmentEntries = computed<DetailEntry[]>(() =>
  (data.value?.inventory?.equipment || [])
    .filter((item) => isValidInventoryEntryName(item))
    .map((item, index) => buildInventoryGearEntry(item, index)),
);

const inventoryConsumableEntries = computed<DetailEntry[]>(() =>
  (data.value?.inventory?.consumables || [])
    .filter((item) => isValidInventoryEntryName(item))
    .map((item, index) => buildInventorySupplyEntry(item, inventoryTabs[1], index)),
);

const inventoryAmmoEntries = computed<DetailEntry[]>(() =>
  (data.value?.inventory?.ammo || [])
    .filter((item) => isValidInventoryEntryName(item))
    .map((item, index) => buildInventorySupplyEntry(item, inventoryTabs[1], index)),
);

const inventoryMaterialEntries = computed<DetailEntry[]>(() =>
  (data.value?.inventory?.materials || [])
    .filter((item) => isValidInventoryEntryName(item))
    .map((item, index) => buildInventorySupplyEntry(item, inventoryTabs[2], index)),
);

const inventoryImportantEntries = computed<DetailEntry[]>(() =>
  (data.value?.inventory?.important || [])
    .filter((item) => isValidInventoryEntryName(item))
    .map((item, index) => buildInventorySupplyEntry(item, inventoryTabs[3], index)),
);

const visibleInventoryEntries = computed<DetailEntry[]>(() => {
  switch (activeInventoryTab.value) {
    case inventoryTabs[0]:
      return inventoryEquipmentEntries.value;
    case inventoryTabs[1]:
      return [
        ...inventoryConsumableEntries.value,
        ...inventoryAmmoEntries.value,
        // 仅当数量 > 0 时显示固定补给项（医疗包、子弹），避免 0 也占位
        ...supplyEntries.value.filter(
          (entry) => (entry.key === 'medkit' || entry.key === 'ammo') && Number(entry.value) > 0,
        ),
      ];
    case inventoryTabs[2]:
      // 仅当数量 > 0 时显示固定补给项（废料）
      return [
        ...inventoryMaterialEntries.value,
        ...supplyEntries.value.filter((entry) => entry.key === 'scrap' && Number(entry.value) > 0),
      ];
    case inventoryTabs[3]:
      return inventoryImportantEntries.value;
    default:
      return [];
  }
});

const fallbackEquipmentBonus = computed(() => {
  if (!data.value) {
    return { maxHp: 0, atk: 0, def: 0, speed: 0, crit: 0 };
  }

  return equipmentKeys.reduce(
    (sum, key) => {
      const name = data.value?.equipment?.[key] || '\u7a7a';
      const meta = mergeMeta(data.value?.equipmentMeta?.[key], equipmentFallbackMeta[name]);
      sum.maxHp += Number(meta.maxHp || 0);
      sum.atk += Number(meta.atk || 0);
      sum.def += Number(meta.def || 0);
      sum.speed += Number(meta.speed || 0);
      sum.crit += Number(meta.crit || 0);
      return sum;
    },
    { maxHp: 0, atk: 0, def: 0, speed: 0, crit: 0 },
  );
});

const effectiveEquipmentBonus = computed(() => {
  const live = data.value?.equipmentBonus;
  const fallback = fallbackEquipmentBonus.value;

  return {
    maxHp: Number(live?.maxHp || fallback.maxHp || 0),
    atk: Number(live?.atk || fallback.atk || 0),
    def: Number(live?.def || fallback.def || 0),
    speed: Number(live?.speed || fallback.speed || 0),
    crit: Number(live?.crit || fallback.crit || 0),
  };
});

const effectiveBonusNotes = computed<string[]>(() => {
  const liveNotes = data.value?.equipmentBonus?.notes || [];
  if (liveNotes.length) return liveNotes;
  if (!data.value) return [];

  return equipmentKeys
    .flatMap((key) => {
      const name = data.value?.equipment?.[key] || '\u7a7a';
      const meta = mergeMeta(data.value?.equipmentMeta?.[key], equipmentFallbackMeta[name]);
      const effects = Array.isArray(meta.effects) ? meta.effects : [];
      return effects.map((effect) => `${name}\uff1a${effect.name}`);
    })
    .filter(Boolean);
});

const equipmentSourceDetails = computed(() => {
  if (!data.value) return [];

  return equipmentKeys.map((key) => {
    const name = data.value?.equipment?.[key] || '\u7a7a';
    const meta = mergeMeta(data.value?.equipmentMeta?.[key], equipmentFallbackMeta[name]);
    const effectNames = (Array.isArray(meta.effects) ? meta.effects : []).map((effect) => effect.name);
    return { key, name, meta, effectNames };
  });
});

const gearBreakdownEntries = computed<BreakdownEntry[]>(() =>
  equipmentSourceDetails.value
    .filter(({ meta }) => Number(meta.atk || 0) > 0 || Number(meta.def || 0) > 0)
    .map(({ name, meta }) => {
      const parts: string[] = [];
      if (Number(meta.atk || 0) > 0) parts.push(`\u653b\u51fb +${Number(meta.atk || 0)}`);
      if (Number(meta.def || 0) > 0) parts.push(`\u9632\u5fa1 +${Number(meta.def || 0)}`);
      return {
        label: name,
        description: parts.join('\uff0c'),
      };
    }),
);

const hpBreakdownEntries = computed<BreakdownEntry[]>(() =>
  equipmentSourceDetails.value
    .filter(({ meta }) => Number(meta.maxHp || 0) > 0)
    .map(({ name, meta }) => ({
      label: name,
      description: `\u751f\u547d +${Number(meta.maxHp || 0)}`,
    })),
);

const noteBreakdownEntries = computed<BreakdownEntry[]>(() =>
  equipmentSourceDetails.value.flatMap(({ name, effectNames }) =>
    effectNames.map((effectName) => ({
      label: name,
      description: effectName,
    })),
  ),
);

const effectiveCombatStats = computed(() => {
  const base = data.value?.player?.baseStats;
  const bonus = effectiveEquipmentBonus.value;
  const derivedAtk = Number(base?.atk || 0) + bonus.atk;
  const derivedDef = Number(base?.def || 0) + bonus.def;
  const derivedSpeed = Number(base?.speed || 0) + bonus.speed;
  const derivedCrit = Number(base?.crit || 0) + bonus.crit;

  return {
    atk: Math.max(Number(data.value?.player?.atk || 0), derivedAtk),
    def: Math.max(Number(data.value?.player?.def || 0), derivedDef),
    speed: Math.max(Number(data.value?.player?.speed || 0), derivedSpeed),
    crit: Math.max(Number(data.value?.player?.crit || 0), derivedCrit),
  };
});

const attributePrimaryStats = computed(() => [
  { key: 'atk', label: 'ATK', value: effectiveCombatStats.value.atk, icon: attributeStatIcons.atk },
  { key: 'def', label: 'DEF', value: effectiveCombatStats.value.def, icon: attributeStatIcons.def },
  { key: 'speed', label: 'SPD', value: effectiveCombatStats.value.speed, icon: attributeStatIcons.speed },
  { key: 'crit', label: 'CRIT', value: `${effectiveCombatStats.value.crit}%`, icon: attributeStatIcons.crit },
]);

const effectiveMaxHp = computed(() => {
  const baseMaxHp = Number(data.value?.player?.baseStats?.maxHp || 0);
  const derivedMaxHp = baseMaxHp + effectiveEquipmentBonus.value.maxHp;
  return Math.max(Number(data.value?.player?.maxHp || 0), derivedMaxHp);
});

const survivalEntries = computed(() => [
  { label: '\u9965\u997f', value: data.value?.player.hunger ?? 0, icon: survivalStatusIcons['\u9965\u997f'] },
  { label: '\u5e72\u6e34', value: data.value?.player.thirst ?? 0, icon: survivalStatusIcons['\u5e72\u6e34'] },
  { label: '\u8f90\u5c04', value: data.value?.player.radiation ?? 0, icon: survivalStatusIcons['\u8f90\u5c04'] },
  { label: '\u4f24\u52bf', value: data.value?.player.injury ?? 0, icon: survivalStatusIcons['\u4f24\u52bf'] },
  { label: '\u8425\u5730\u5371\u9669', value: data.value?.status.campDanger ?? 0, icon: survivalStatusIcons['\u8425\u5730\u5371\u9669'] },
]);

function toggleSurvival() {
  isSurvivalOpen.value = !isSurvivalOpen.value;
}

function openDetail(entry: DetailEntry) {
  selectedDetail.value = entry;
}

function closeDetail() {
  selectedDetail.value = null;
}

/** 部位名称 -> 装备槽 key */
const slotLabelToKey: Record<string, EquipmentKey> = {
  [equipmentLabels.mainWeapon]: 'mainWeapon',
  [equipmentLabels.subWeapon]: 'subWeapon',
  [equipmentLabels.head]: 'head',
  [equipmentLabels.chest]: 'chest',
  [equipmentLabels.hands]: 'hands',
  [equipmentLabels.legs]: 'legs',
  [equipmentLabels.feet]: 'feet',
  [equipmentLabels.accessory1]: 'accessory1',
  [equipmentLabels.accessory2]: 'accessory2',
};

const canEquip = computed(
  () =>
    selectedDetail.value?.source === 'inventory-gear' &&
    selectedDetail.value?.inventoryGearIndex !== undefined,
);
const canUnequip = computed(
  () =>
    selectedDetail.value?.source === 'slot' &&
    selectedDetail.value?.name !== '\u7a7a',
);

function equipFromInventory(inventoryIndex: number) {
  const raw = data.value;
  if (!raw?.inventory?.equipment) return;
  const list = raw.inventory.equipment;
  const item = list[inventoryIndex];
  if (!item) return;
  const itemName = (item.name || '').trim();
  // 优先用弹窗里已解析的部位（来自 buildInventoryGearEntry 的 meta.slot），避免变量里 item.slot 缺失或编码问题
  const entrySlot =
    selectedDetail.value?.source === 'inventory-gear' &&
    selectedDetail.value?.slotOrCategory &&
    slotLabelToKey[selectedDetail.value.slotOrCategory]
      ? selectedDetail.value.slotOrCategory
      : '';
  const slotLabel = (entrySlot || (item.slot || '').trim() || equipmentFallbackMeta[itemName]?.slot || '').trim();
  const equipmentKey = slotLabelToKey[slotLabel];
  if (!equipmentKey) {
    console.warn('[状态栏] 无法解析装备部位，请确保物品有 slot 或为已知装备名:', { slotLabel, itemName, entrySlot });
    return;
  }
  const currentName = raw.equipment?.[equipmentKey] || '\u7a7a';
  const currentMeta = raw.equipmentMeta?.[equipmentKey];
  const newInventoryEquipment = list.filter((_, i) => i !== inventoryIndex);
  if (currentName && currentName !== '\u7a7a' && currentMeta) {
    newInventoryEquipment.push({
      ...currentMeta,
      name: currentName,
      id: `gear-${Date.now()}-${equipmentKey}`,
      quantity: 1,
    });
  }
  raw.inventory.equipment = newInventoryEquipment;
  raw.equipment = { ...raw.equipment, [equipmentKey]: item.name || '\u7a7a' };
  raw.equipmentMeta = {
    ...raw.equipmentMeta,
    [equipmentKey]: {
      name: item.name ?? '',
      slot: item.slot ?? equipmentLabels[equipmentKey],
      grade: item.grade ?? '\u666e\u901a',
      summary: item.summary ?? '\u65e0',
      flavor: item.flavor ?? '\u65e0',
      maxHp: Number(item.maxHp ?? 0),
      atk: Number(item.atk ?? 0),
      def: Number(item.def ?? 0),
      speed: Number(item.speed ?? 0),
      crit: Number(item.crit ?? 0),
      effects: Array.isArray(item.effects) ? item.effects : [],
    },
  };
  console.info('[状态栏] 已装备:', itemName, '->', equipmentLabels[equipmentKey]);
  closeDetail();
}

function unequipSlot(equipmentKey: EquipmentKey) {
  const raw = data.value;
  if (!raw?.equipment) return;
  const name = raw.equipment[equipmentKey];
  if (!name || name === '\u7a7a') return;
  const meta = raw.equipmentMeta?.[equipmentKey] || {};
  const newGear = {
    ...meta,
    name,
    id: `gear-${Date.now()}-${equipmentKey}`,
    quantity: 1,
  };
  raw.inventory = {
    ...raw.inventory,
    equipment: [...(raw.inventory?.equipment || []), newGear],
  };
  raw.equipment = { ...raw.equipment, [equipmentKey]: '\u7a7a' };
  raw.equipmentMeta = {
    ...raw.equipmentMeta,
    [equipmentKey]: {
      name: '',
      slot: equipmentLabels[equipmentKey],
      grade: '\u666e\u901a',
      summary: '\u65e0',
      flavor: '\u65e0',
      maxHp: 0,
      atk: 0,
      def: 0,
      speed: 0,
      crit: 0,
      effects: [],
    },
  };
  console.info('[状态栏] 已脱下:', name, equipmentLabels[equipmentKey]);
  closeDetail();
}

function openBreakdown(kind: 'gear' | 'hp' | 'notes') {
  if (kind === 'gear') {
    selectedBreakdown.value = {
      title: '\u88c5\u5907\u52a0\u6210',
      summary: '\u8fd9\u91cc\u663e\u793a\u54ea\u4e9b\u88c5\u5907\u6b63\u5728\u4e3a\u653b\u51fb\u548c\u9632\u5fa1\u63d0\u4f9b\u52a0\u6210\u3002',
      items: gearBreakdownEntries.value,
    };
    return;
  }

  if (kind === 'hp') {
    selectedBreakdown.value = {
      title: '\u751f\u547d\u52a0\u6210',
      summary: '\u8fd9\u91cc\u663e\u793a\u63d0\u5347\u6700\u5927\u751f\u547d\u7684\u88c5\u5907\u6765\u6e90\u3002',
      items: hpBreakdownEntries.value,
    };
    return;
  }

  selectedBreakdown.value = {
    title: '\u8bcd\u6761\u6765\u6e90',
    summary: '\u8fd9\u91cc\u663e\u793a\u5f53\u524d\u751f\u6548\u7684\u88c5\u5907\u8bcd\u6761\u6765\u81ea\u54ea\u4e9b\u7269\u54c1\u3002',
    items: noteBreakdownEntries.value,
  };
}

function closeBreakdown() {
  selectedBreakdown.value = null;
}

function persistAvatar(value: string | null) {
  if (data.value?.log) {
    data.value.log.avatar = value || '';
  }

  try {
    if (value) {
      localStorage.setItem(STORAGE_AVATAR_KEY, value);
    } else {
      localStorage.removeItem(STORAGE_AVATAR_KEY);
    }
  } catch {}
}

function triggerAvatarUpload() {
  avatarInputRef.value?.click();
}

function onAvatarChange(event: Event) {
  const input = event.target as HTMLInputElement | null;
  const file = input?.files?.[0];
  if (!file) return;

  const reader = new FileReader();
  reader.onload = () => {
    const result = typeof reader.result === 'string' ? reader.result : null;
    if (!result) return;
    avatarUrl.value = result;
    persistAvatar(result);
  };
  reader.readAsDataURL(file);

  if (input) input.value = '';
}

onMounted(() => {
  const syncedAvatar = data.value?.log?.avatar || '';
  if (syncedAvatar) {
    avatarUrl.value = syncedAvatar;
  } else {
    try {
      const saved = localStorage.getItem(STORAGE_AVATAR_KEY);
      if (saved) {
        avatarUrl.value = saved;
        persistAvatar(saved);
      }
    } catch {}
  }

  syncLootInventoryFromLatestMessage();
});

watch(
  () => data.value?.log?.avatar,
  (value) => {
    if (value && value !== avatarUrl.value) {
      avatarUrl.value = value;
    }
  },
);

watch(
  () => data.value?.log?.lootHint,
  () => {
    syncLootInventoryFromLatestMessage();
  },
);
</script>

